  if (rate < 0 || rate > 1) {
    throw new Error('Invalid discount rate');
  }
  const discount = price * rate;
  const total = price - discount;
  return Number.isFinite(total) && total >= 0 ? total : price;
}

export function mergeCarts(a: Cart, b: Cart): Cart {
  const merged = { ...a, ...b };
  // Warn on key collisions that could hide data
  const collisions = Object.keys(merged).filter(k => a.hasOwnProperty(k) && b.hasOwnProperty(k) && a[k] !== b[k]);
