export function calculateDiscount(price: number, quantity: number, discountRate: number): number {
  if (isNaN(price) || isNaN(quantity) || isNaN(discountRate)) {
    return 0;
  }
  if (quantity <= 0) {
    return 0;
  }
  const safeRate = Math.max(0, Math.min(1, discountRate));
  const discount = price * safeRate;
  const total = price * quantity;
  const discountedTotal = total - discount;
  return Number.isFinite(discountedTotal) ? discountedTotal : 0;
}
