export function calculateTax(income: number): number {
  if (typeof income !== 'number' || !Number.isFinite(income)) {
    throw new Error('Income must be a finite number');
  }
  if (income < 0) {
    throw new Error('Income cannot be negative');
  }
  const brackets = [{limit: 10000, rate: 0.1}, {limit: 40000, rate: 0.2}, {limit: Infinity, rate: 0.3}];
  let tax = 0;
  let remaining = income;
  for (const {limit, rate} of brackets) {
    if (remaining <= 0) break;
    const prevLimit = brackets[ brackets.indexOf({limit, rate}) > 0 ? brackets[ brackets.indexOf({limit, rate}) - 1].limit : 0];
    const taxable = Math.min(remaining, limit - prevLimit);
    tax += taxable * rate;
    remaining -= taxable;
  }
  return tax;
}
