export function calculateNetPrice(basePrice: number, discountPercent: number, taxRate: number): number {
  if (typeof basePrice !== 'number' || isNaN(basePrice) || basePrice < 0) {
    throw new Error('basePrice must be a non‑negative number');
  }
  if (typeof discountPercent !== 'number' || isNaN(discountPercent) || discountPercent < 0 || discountPercent > 100) {
    throw new Error('discountPercent must be between 0 and 100');
  }
  if (typeof taxRate !== 'number' || isNaN(taxRate) || taxRate < 0 || taxRate > 1) {
    throw new Error('taxRate must be between 0 and 1');
  }

  const discounted = basePrice * (1 - discountPercent / 100);
  const withTax = discounted * (1 + taxRate);
  if (!Number.isFinite(withTax)) {
    throw new Error('Resulting price is not finite');
  }
  return withTax;
}
